          margin: 0 0 0.5rem 0;
          color: #64748b;
          font-size: 0.9rem;
          text-transform: uppercase;
        }
        .insight-item p {
          margin: 0;
          font-size: 1.1rem;
          font-weight: 600;
          color: #1a1a2e;
        }
        .analytics-section-end {
          margin-top: 2rem;
          display: flex;
          flex-direction: column;
          gap: 2rem;
        }
        .report-chart-card {
          background: white;
          padding: 2rem;
          border-radius: 12px;
          box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05);
          border: 1px solid #f1f5f9;
        }
        .chart-header {
          margin-bottom: 2rem;
        }
        .chart-header h3 {
          margin: 0;
          color: #1a3a52;
          font-size: 1.25rem;
          font-weight: 700;
        }
        .chart-header p {
          margin: 0.25rem 0 0 0;
          color: #64748b;
          font-size: 0.875rem;
        }
        .analytics-charts-grid {
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(400px, 1fr));
          gap: 2rem;
        }
        @media (max-width: 1024px) {
          .analytics-charts-grid {
            grid-template-columns: 1fr;
          }
        }
      `}</style>
    </div>
  );
};

export default Reports;
